import React from 'react';
import { Pie } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend
} from 'chart.js';

ChartJS.register(ArcElement, Tooltip, Legend);

const DataInsightsPieChart = ({ data }) => {
  if (!Array.isArray(data) || data.length === 0) return null;

  const sample = data[0];

  // Detect label & value fields dynamically
  const labelKey = Object.keys(sample).find(
    key => typeof sample[key] === 'string'
  );
  const valueKey = Object.keys(sample).find(
    key => typeof sample[key] === 'number'
  );

  if (!labelKey || !valueKey) return null;

  const chartData = {
    labels: data.map(item => item[labelKey]),
    datasets: [
      {
        data: data.map(item => item[valueKey]),
        backgroundColor: [
          '#6366F1',
          '#22C55E',
          '#F97316',
          '#EF4444',
          '#14B8A6',
          '#EAB308',
          '#8B5CF6'
        ]
      }
    ]
  };

  return (
    <div style={{ maxWidth: 360, marginTop: 16 }}>
      <Pie data={chartData} />
    </div>
  );
};

export default DataInsightsPieChart;
